"""Sandboxed executor for Pandas and Polars code generated by LLMs.

Design:
  - Runs generated code in a subprocess with a timeout (default 10s)
  - Passes tables as serialized JSON, deserializes inside subprocess
  - Subprocess has no network access (Windows: limited enforcement)
  - Returns (result_str, error_str, exec_ms)

Code format expected from LLM:
  - Pandas: uses `tables` dict of DataFrames; last expression is result
  - Polars: uses `tables` dict of pl.DataFrames; last expression is result

The executor wraps the generated code with:
  1. Import + table reconstruction
  2. User code block
  3. print(result) on the final expression
"""
from __future__ import annotations
import json
import re
import subprocess
import sys
import tempfile
import time
from pathlib import Path


EXEC_TIMEOUT = 15  # seconds


# ---------------------------------------------------------------------------
# Code extractors
# ---------------------------------------------------------------------------

def extract_python(response: str, fence: str = "python") -> str:
    """Extract first ```python ... ``` block from response."""
    pattern = rf"```{fence}\s*(.*?)```"
    m = re.search(pattern, response, re.DOTALL | re.IGNORECASE)
    if m:
        return m.group(1).strip()
    # Fallback: any ``` block
    m = re.search(r"```\s*(.*?)```", response, re.DOTALL)
    if m:
        return m.group(1).strip()
    # Last resort: return full response stripped
    return response.strip()


# ---------------------------------------------------------------------------
# Subprocess wrappers
# ---------------------------------------------------------------------------

_PANDAS_BOOTSTRAP = """
import json, sys, pandas as pd, io
_tables_raw = json.loads(sys.stdin.read())
tables = {name: pd.DataFrame(rows) for name, rows in _tables_raw.items()}
# Numeric coercion: try converting string columns to numeric
for _df in tables.values():
    for _col in list(_df.columns):
        try:
            _df[_col] = pd.to_numeric(_df[_col])
        except Exception:
            pass
"""

_POLARS_BOOTSTRAP = """
import json, sys, io
import polars as pl
_tables_raw = json.loads(sys.stdin.read())
def _infer(rows):
    df = pl.DataFrame(rows)
    for col in df.columns:
        try:
            df = df.with_columns(pl.col(col).cast(pl.Float64, strict=False))
        except Exception:
            pass
    return df
tables = {name: _infer(rows) for name, rows in _tables_raw.items()}
"""

_RESULT_WRAPPER = """
_result = ({expr})
if hasattr(_result, 'to_list'):
    _result = _result.to_list()
if hasattr(_result, 'tolist'):
    _result = _result.tolist()
print(str(_result))
"""


def _make_script(bootstrap: str, user_code: str) -> str:
    """Wrap user code with bootstrap and result extraction."""
    lines = user_code.strip().splitlines()
    if not lines:
        return bootstrap + "\nprint('EMPTY')"

    last_line = lines[-1].strip()
    body = "\n".join(lines[:-1])

    # If last line is an assignment, just run it then print the assigned var
    if "=" in last_line and not last_line.startswith("print"):
        var_name = last_line.split("=")[0].strip()
        script = bootstrap + "\n" + body + "\n" + last_line + f"\nprint(str({var_name}))\n"
    else:
        script = (bootstrap + "\n" + body + "\n" +
                  _RESULT_WRAPPER.format(expr=last_line))
    return script


def execute_python(
    code: str,
    tables: dict,
    library: str = "pandas",
    timeout: int = EXEC_TIMEOUT,
) -> tuple[str, str, int]:
    """Execute generated Python code in a subprocess.

    Args:
      code      — LLM-generated Python code (may be empty/malformed)
      tables    — dict of table_name -> list of row dicts
      library   — "pandas" or "polars"
      timeout   — subprocess timeout in seconds

    Returns:
      (result_str, error_str, exec_ms)
      result_str: cleaned string representation of query result, "" on error
      error_str:  error message, "" on success
      exec_ms:    execution time in milliseconds
    """
    bootstrap = _PANDAS_BOOTSTRAP if library == "pandas" else _POLARS_BOOTSTRAP
    script = _make_script(bootstrap, code)
    tables_json = json.dumps(tables, ensure_ascii=False)

    with tempfile.NamedTemporaryFile("w", suffix=".py", delete=False,
                                    encoding="utf-8") as f:
        f.write(script)
        script_path = f.name

    t0 = time.time()
    try:
        proc = subprocess.run(
            [sys.executable, script_path],
            input=tables_json,
            capture_output=True,
            text=True,
            timeout=timeout,
            encoding="utf-8",
            errors="replace",
        )
        exec_ms = int((time.time() - t0) * 1000)

        if proc.returncode != 0:
            err = proc.stderr.strip().splitlines()
            return "", err[-1] if err else "non-zero exit", exec_ms

        result = proc.stdout.strip()
        return result, "", exec_ms

    except subprocess.TimeoutExpired:
        exec_ms = int(timeout * 1000)
        return "", f"TIMEOUT after {timeout}s", exec_ms
    except Exception as e:
        exec_ms = int((time.time() - t0) * 1000)
        return "", str(e), exec_ms
    finally:
        try:
            Path(script_path).unlink()
        except Exception:
            pass


# ---------------------------------------------------------------------------
# Result scoring (mirrors score_sql from m1)
# ---------------------------------------------------------------------------

def score_python_result(
    q: dict,
    result_str: str,
    gt: dict,
    tol: float = 0.01,
) -> tuple[bool, str, str]:
    """Score a Python execution result against ground truth.

    Mirrors the interface of score_sql:
    Returns (ok, reason, result_str).
    """
    if not result_str:
        return False, "no_result", ""

    gt_val = gt.get(q["key"])
    q_type = q.get("type", "")

    try:
        if q_type in ("count", "numeric"):
            result_num = float(result_str.replace(",", "."))
            gt_num = float(gt_val)
            if abs(gt_num) < 1e-9:
                ok = abs(result_num) < 1e-9
            else:
                ok = abs(result_num - gt_num) / abs(gt_num) <= tol
            reason = "correct" if ok else "wrong_value"
            return ok, reason, result_str

        elif q_type == "string":
            result_clean = result_str.strip().strip("'\"[]")
            gt_clean = str(gt_val).strip()
            ok = result_clean.lower() == gt_clean.lower()
            reason = "correct" if ok else "wrong_name"
            return ok, reason, result_str

    except Exception as e:
        return False, f"parse_error:{e}", result_str

    return False, "unknown_type", result_str
